/// <summary>
///
/// </summary>
private void UpdateNetWeight()
{
    VendParameters      VendParameters = VendParameters::find();

    //if(ETGPurchLineCoCOAQuality.GrossWeight !=0 && ETGPurchLineCoCOAQuality.WeightofBags !=0 
     //   && ETGPurchLineCoCOAQuality.Humidityreaction !=0 && ETGPurchLineCoCOAQuality.Qualityreaction !=0)
    {
        ETGPurchLineCoCOAQuality.NetWeight = ETGPurchLineCoCOAQuality.GrossWeight - ETGPurchLineCoCOAQuality.WeightofBags
                                            - ETGPurchLineCoCOAQuality.Humidityreaction - ETGPurchLineCoCOAQuality.Qualityreaction;
        ETGPurchLineCoCOAQuality.Onaccount = ETGPurchLineCoCOAQuality.NetWeight* VendParameters.ETGOnAccountFactor;
        ETGPurchLineCoCOAQuality.BicAmount = ETGPurchLineCoCOAQuality.NetWeight* VendParameters.ETGBICAmountFactor;

    }
}

