/// <summary>
///
/// </summary>
/// <returns></returns>
public int active()
{
    int ret;

    ret = super();

    if(curExt() == 'o018')
    {
        TransportDetails.allowEdit(PurchTable.PurchStatus == PurchStatus::Backorder ||
                                PurchTable.PurchStatus == PurchStatus::Received || PurchTable.PurchStatus == PurchStatus::Invoiced);
        Packing.allowEdit(PurchTable.PurchStatus == PurchStatus::Backorder ||
                                PurchTable.PurchStatus == PurchStatus::Received || PurchTable.PurchStatus == PurchStatus::Invoiced);
        Pricing.allowEdit(PurchTable.PurchStatus == PurchStatus::Backorder ||
                                PurchTable.PurchStatus == PurchStatus::Received || PurchTable.PurchStatus == PurchStatus::Invoiced);
        QualityParameter.allowEdit(PurchTable.PurchStatus == PurchStatus::Backorder ||
                                PurchTable.PurchStatus == PurchStatus::Received || PurchTable.PurchStatus == PurchStatus::Invoiced);
        InformativeDetails.allowEdit(PurchTable.PurchStatus == PurchStatus::Backorder ||
                                PurchTable.PurchStatus == PurchStatus::Received || PurchTable.PurchStatus == PurchStatus::Invoiced);
        ETGPurchLineCoCOAQuality_ds.object(fieldNum(ETGPurchLineCoCOAQuality,Date1)).allowEdit(PurchTable.PurchStatus == PurchStatus::Backorder ||
                                PurchTable.PurchStatus == PurchStatus::Received || PurchTable.PurchStatus == PurchStatus::Invoiced);
        ETGPurchLineCoCOAQuality_ds.object(fieldNum(ETGPurchLineCoCOAQuality,GRN)).allowEdit(PurchTable.PurchStatus == PurchStatus::Backorder ||
                                PurchTable.PurchStatus == PurchStatus::Received || PurchTable.PurchStatus == PurchStatus::Invoiced);
    }
    else
    {

        TransportDetails.allowEdit(PurchTable.PurchStatus == PurchStatus::Backorder ||
                                PurchTable.PurchStatus == PurchStatus::Received);
        Packing.allowEdit(PurchTable.PurchStatus == PurchStatus::Backorder ||
                                PurchTable.PurchStatus == PurchStatus::Received);
        Pricing.allowEdit(PurchTable.PurchStatus == PurchStatus::Backorder ||
                                PurchTable.PurchStatus == PurchStatus::Received);
        // QualityParameter.allowEdit(PurchTable.PurchStatus == PurchStatus::Backorder ||
        //                           PurchTable.PurchStatus == PurchStatus::Received);

        ETGPurchLineCoCOAQuality_ds.object(fieldNum(ETGPurchLineCoCOAQuality,Date1)).allowEdit(PurchTable.PurchStatus == PurchStatus::Backorder ||
                                PurchTable.PurchStatus == PurchStatus::Received);

        ETGPurchLineCoCOAQuality_ds.object(fieldNum(ETGPurchLineCoCOAQuality,GRN)).allowEdit(PurchTable.PurchStatus == PurchStatus::Backorder ||
                                PurchTable.PurchStatus == PurchStatus::Received);
     }



    return ret;
}

/// <summary>
///
/// </summary>
public void clicked()
{
    element.UpdateNetWeight();
    //element.updateAPValue();
    super();
    ttsbegin;
    PurchLine.PurchQty = ETGPurchLineCoCOAQuality.NetWeight;
    purchLine.validateField(fieldnum(PurchLine, PurchQty));
    purchLine.modifiedField(fieldnum(PurchLine, PurchQty));
    purchLine.QtyOrdered                = purchLine.PurchQty;
    purchLine.RemainInventPhysical      = purchLine.PurchQty;
    purchLine.RemainPurchPhysical       = purchLine.PurchQty;           
    PurchLine.modifiedField(fieldNum(PurchLine,PurchPrice));
    PurchLine.Update();
    ttscommit;
}

/// <summary>
///
/// </summary>
/// <returns></returns>
public boolean modified()
{
    boolean ret;

    ret = super();

    ETGPurchLineCoCOAQuality.Weightloss = ETGPurchLineCoCOAQuality.NetWeight - ETGPurchLineCoCOAQuality.GRN;

    return ret;
}

/// <summary>
///
/// </summary>
/// <returns></returns>
public boolean modified()
{
    boolean ret;

    ret = super();
    if(ETGPurchLineCoCOAQuality.NetWeight != 0)
    {
        ETGPurchLineCoCOAQuality.LandedPrice = ETGPurchLineCoCOAQuality.MTNValue/ETGPurchLineCoCOAQuality.NetWeight;
    }
    return ret;
}
